import Foundation

func solve(s: String, k: Int64) -> String {
    var result: [Character] = []
    for char in s {
        switch char {
        case "a"..."z":
            result.append(char)
        case "*":
            if !result.isEmpty {
                result.removeLast()
            }
        case "#":
            let copy = result
            result.append(contentsOf: copy)
        case "%":
            result = result.reversed()
        default:
            break
        }
    }

    if k < 0 || k >= Int64(result.count) {
        return "."
    }

    return String(result[k])
}
